#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& stream) {
        // Serialize packet_id
        stream.serialise(packet_id);

        // Serialize username with length prefix
        stream.serialise(hexi::length_prefix{username});

        // Serialize scores with count first, then elements
        stream.serialise(hexi::length_prefix{scores});

        // Serialize metadata as null-terminated string
        stream.serialise(hexi::null_terminated{metadata});
    }
};

std::vector<uint8_t> serialize_packet(const NetworkPacket& packet) {
    // Create a buffer to hold the serialized data
    std::vector<uint8_t> buffer;

    // Create a Hexi output stream that writes to the buffer
    hexi::output_stream stream(buffer);

    // Serialize the packet using the stream
    const_cast<NetworkPacket&>(packet).serialise(stream);

    return buffer;
}
```

