struct PacketHeader {
    uint32_t magic;
    uint16_t version;
    uint16_t flags;
};

PacketHeader read_header_with_span(const std::span<const uint8_t> buffer) {
    // Create buffer adaptor from the span
    hexi::buffer_adaptor adaptor(buffer.data(), buffer.size());

    // Check available data using buffer_adaptor methods
    if (adaptor.available() < sizeof(PacketHeader)) {
        throw std::runtime_error("Insufficient data for header");
    }

    // Get the read pointer
    const uint8_t* read_ptr = adaptor.read_ptr();

    // Create binary_stream for zero-copy operations
    hexi::binary_stream stream(adaptor);

    // Get a zero-copy view of the header using binary_stream
    auto header_view = stream.peek_bytes(sizeof(PacketHeader));

    // Ensure we have a valid view
    if (header_view.size() < sizeof(PacketHeader)) {
        throw std::runtime_error("Failed to get zero-copy view of header");
    }

    // Convert the view to PacketHeader (this is still zero-copy in spirit)
    // We need to be careful about alignment, so we'll use memcpy
    PacketHeader header;
    std::memcpy(&header, header_view.data(), sizeof(PacketHeader));

    // Advance the read pointer by the header size
    stream.skip(sizeof(PacketHeader));

    return header;
}
