```cpp
#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>

std::vector<uint8_t> read_file_data(const std::filesystem::path& file_path, size_t bytes_to_read) {
    // Create a file_buffer object for reading
    hexi::file_buffer file(file_path, std::ios::in | std::ios::binary);

    if (!file.is_open()) {
        throw std::runtime_error("Failed to open file for reading: " + file_path.string());
    }

    // Determine how many bytes we can actually read
    size_t available_bytes = file.size();
    size_t bytes_to_read_actual = std::min(bytes_to_read, available_bytes);

    // Create destination buffer and read data
    std::vector<uint8_t> buffer(bytes_to_read_actual);
    file.read(reinterpret_cast<char*>(buffer.data()), bytes_to_read_actual);

    return buffer;
}

std::vector<uint8_t> preview_file_data(const std::filesystem::path& file_path, size_t bytes_to_preview) {
    // Create a file_buffer object for reading
    hexi::file_buffer file(file_path, std::ios::in | std::ios::binary);

    if (!file.is_open()) {
        throw std::runtime_error("Failed to open file for preview: " + file_path.string());
    }

    // Get current position to restore later
    size_t current_pos = file.tell();

    // Determine how many bytes we can actually preview
    size_t available_bytes = file.size() - current_pos;
    size_t bytes_to_preview_actual = std::min(bytes_to_preview, available_bytes);

    // Create destination buffer and read data
    std::vector<uint8_t> buffer(bytes_to_preview_actual);
    file.read(reinterpret_cast<char*>(buffer.data()), bytes_to_preview_actual);

    // Restore original position
    file.seek(current_pos);

    return buffer;
}

void write_file_data(const std::filesystem::path& file_path, const std::vector<uint8_t>& data) {
    // Create a file_buffer object for writing (truncate existing file)
    hexi::file_buffer file(file_path, std::ios::out | std::ios::binary | std::ios::trunc);

    if (!file.is_open()) {
        throw std::runtime_error("Failed to open file for writing: " + file_path.string());
    }

    // Write data to file
    file.write(reinterpret_cast<const char*>(data.data()), data.size());

    // Flush to ensure data is written
    file.flush();
}

size_t get_file_size(const std::filesystem::path& file_path) {
    // Create a file_buffer object for reading
    hexi::file_buffer file(file_path, std::ios::in | std::ios::binary);

    if (!file.is_open()) {
        throw std::runtime_error("Failed to open file for size check: " + file_path.string());
    }

    // Return the size of readable data
    return file.size();
}
```

