#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <string>

void write_string_to_stream(hexi::pmc::binary_stream_writer& writer, const std::string& str) {
    // Write the length of the string as a prefix
    writer.write(static_cast<uint32_t>(str.length()));

    // Write the string data
    if (!str.empty()) {
        writer.write(str.data(), str.length());
    }
}

std::string read_string_from_stream(hexi::pmc::binary_stream_reader& reader) {
    // Read the length prefix
    uint32_t length;
    reader.read(length);

    // Read the string data
    std::string str;
    if (length > 0) {
        str.resize(length);
        reader.read(&str[0], length);
    }

    return str;
}
```

This implementation follows the common pattern for prefixed string serialization:

1. **Writing**: First writes the string length as a 32-bit unsigned integer prefix, then writes the actual string characters.

2. **Reading**: First reads the length prefix, then reads that many characters into a string.

The code handles empty strings correctly by checking the length before attempting to read/write the character data. The use of `uint32_t` for the length prefix is a common convention that allows strings up to 4GB in length while maintaining a fixed-size prefix.

