#include <vector>
#include <cstdint>

std::size_t find_byte_in_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, std::byte value) {
    // Create a buffer reader from the adaptor
    hexi::pmc::buffer_read reader(buffer);

    // Save the current position
    std::size_t original_pos = reader.tell();

    // Seek to the beginning
    reader.seek(0);

    // Search for the byte value
    while (reader.remaining() > 0) {
        std::byte current_byte = reader.read_byte();
        if (current_byte == value) {
            // Found the byte, return the position (current position - 1 since read_byte advances)
            std::size_t found_pos = reader.tell() - 1;
            // Restore original position
            reader.seek(original_pos);
            return found_pos;
        }
    }

    // Not found, restore position and return npos
    reader.seek(original_pos);
    return hexi::pmc::buffer_read::npos;
}

std::size_t find_delimiter_position(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, std::byte delimiter) {
    // This is essentially the same as find_byte_in_buffer, but we can reuse that function
    return find_byte_in_buffer(buffer, delimiter);
}

bool check_buffer_contains(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, std::byte value) {
    // Use find_byte_in_buffer and check if result is not npos
    return find_byte_in_buffer(buffer, value) != hexi::pmc::buffer_read::npos;
}

